import { test, expect } from '@playwright/test';

test('Amazon SG - No results message for gibberish search', async ({ page }) => {
  // 1. Launch browser → Amazon SG
  await page.goto('https://www.amazon.sg/');

  // 2. Search for "asdasd123!@#"
  const searchBox = page.getByRole('combobox', { name: /search/i });
  await expect(searchBox).toBeVisible({ timeout: 10000 });
  await searchBox.fill('asdasd123!@#');
  await page.getByRole('button', { name: /search/i }).click();

  // 3. Wait for results page
  await page.waitForLoadState('domcontentloaded');
  await expect(page).toHaveURL(/k=asdasd123!@#/);

  // 4. Validate "no results" or limited results message appears
  // Amazon SG may show: "No results for", or "did not match any products", or similar
  const noResultsLocator = page.getByText('No results for', { exact: false });
  const didNotMatchLocator = page.getByText('did not match any products', { exact: false });
  const suggestionsLocator = page.getByText('Try checking your spelling or use more general terms', { exact: false });

  const foundNoResults =
    (await noResultsLocator.count()) > 0 ||
    (await didNotMatchLocator.count()) > 0 ||
    (await suggestionsLocator.count()) > 0;

  expect(foundNoResults).toBeTruthy();

  // 5. Close browser (handled by Playwright test runner)
});
